// ============================================================
// BUILD ALERT PAYLOAD — Workflow 2, Node 2
// ============================================================

const data = $json;
const emp = data.employee || {};
const allDeals = data.deals || [];
const max = data.maxDealsPerMsg || 8;
const dealListUrl = data.dealListUrl || `${data.bitrixDomain}/crm/deal/`;
const senderName = data.fromName || 'Averlon CRM';

// Determine current alert time label (IST-aware)
const now = new Date();
const IST_OFFSET_MS = 5.5 * 60 * 60 * 1000;
const nowIST = new Date(now.getTime() + IST_OFFSET_MS);
const hour = nowIST.getUTCHours();

let alertLabel = '10:00 AM';
if (hour === 13) alertLabel = '1:00 PM';
else if (hour === 17) alertLabel = '5:00 PM';
else if (hour === 18) alertLabel = '6:30 PM';

// ---- VALIDATE & LIMIT TO MAX 8 ----
if (!Array.isArray(allDeals) || allDeals.length === 0) {
  return [{ json: { error: "Deals data is missing or invalid", debug: data } }];
}

const shownDeals = allDeals.slice(0, max);
const remainingCount = allDeals.length - shownDeals.length;

// ---- BUILD DEAL LIST TEXT (for Bitrix24 notification) ----
function dealStatusLabel(deal) {
  if (deal.status === 'PAST_OVERDUE') return `⚠️ OVERDUE by ${deal.daysOverdue} day(s)`;
  if (deal.status === 'TODAY') return `🟠 Due TODAY (will be overdue tomorrow)`;
  return `🔔 Due on ${deal.deadlineFormatted}`;
}

let bitrixBody = `📋 *Overdue Deal Alert — ${alertLabel}*\n\n`;
bitrixBody += `Hi ${emp.name || 'User'},\n\nYou have ${data.totalDeals} deal(s) requiring your attention:\n\n`;

shownDeals.forEach((deal, i) => {
  const subject = deal.subject || deal.entityTitle || 'Unnamed Deal';
  const dueDate = deal.deadlineFormatted || 'No date';
  const url = deal.url || data.bitrixDomain;

  bitrixBody += `${i + 1}. *${subject}*\n`;
  bitrixBody += `   📅 Due: ${dueDate}\n`;
  bitrixBody += `   ${dealStatusLabel(deal)}\n`;
  bitrixBody += `   🔗 [Open Deal](${url})\n\n`;
});

if (remainingCount > 0) {
  bitrixBody += `➕ And *${remainingCount} more deal(s)* remaining.\n`;
  bitrixBody += `[Click here to view all deals](${dealListUrl})\n\n`;
}

bitrixBody += `— ${senderName}`;

// ---- BUILD HTML EMAIL (for Outlook) ----
function dealRowHtml(deal, index) {
  const statusColor = deal.status === 'PAST_OVERDUE' ? '#E24B4A'
    : deal.status === 'TODAY' ? '#BA7517' : '#0F6E56';
  const statusText = deal.status === 'PAST_OVERDUE'
    ? `Overdue by ${deal.daysOverdue} day(s)`
    : deal.status === 'TODAY' ? 'Due Today' : `Due on ${deal.deadlineFormatted}`;

  const subject = deal.subject || deal.entityTitle || 'Unnamed Deal';
  const dueDate = deal.deadlineFormatted || 'No date';
  const url = deal.url || '#';

  return `
  <tr style="border-bottom: 1px solid #e8e8e8;">
    <td style="padding: 12px 8px; font-size: 14px; color: #2c2c2a; font-weight: 500;">${index + 1}. ${subject}</td>
    <td style="padding: 12px 8px; font-size: 13px; color: #5f5e5a;">${dueDate}</td>
    <td style="padding: 12px 8px;">
      <span style="background: ${statusColor}22; color: ${statusColor}; font-size: 12px; font-weight: 500; padding: 3px 10px; border-radius: 12px;">${statusText}</span>
    </td>
    <td style="padding: 12px 8px;">
      <a href="${url}" style="background: #185FA5; color: white; font-size: 12px; padding: 5px 12px; border-radius: 6px; text-decoration: none; display: inline-block;">View →</a>
    </td>
  </tr>`;
}

const dealRowsHtml = shownDeals.map((d, i) => dealRowHtml(d, i)).join('');

const remainingHtml = remainingCount > 0 ? `
  <div style="margin: 16px 0; padding: 12px 16px; background: #E6F1FB; border-radius: 8px; font-size: 14px; color: #185FA5;">
    And <strong>${remainingCount} more deal(s)</strong> remaining. 
    <a href="${dealListUrl}" style="color: #185FA5; font-weight: 600;">Click here to view all →</a>
  </div>` : '';

const emailHtml = `
<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"></head>
<body style="margin: 0; padding: 0; background: #f4f4f0; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;">
  <div style="max-width: 620px; margin: 32px auto; background: white; border-radius: 12px; overflow: hidden; border: 1px solid #d3d1c7;">
    <div style="background: #185FA5; padding: 28px 32px;">
      <div style="font-size: 11px; color: #B5D4F4; font-weight: 600; letter-spacing: 1px; text-transform: uppercase; margin-bottom: 6px;">${senderName}</div>
      <h1 style="margin: 0; color: white; font-size: 22px; font-weight: 600;">Deal Overdue Alert</h1>
      <div style="color: #B5D4F4; font-size: 13px; margin-top: 6px;">${alertLabel} · ${data.runDate}</div>
    </div>
    <div style="padding: 24px 32px 0;">
      <p style="font-size: 15px; color: #2c2c2a; margin: 0 0 8px;">Hi <strong>${emp.name || 'User'}</strong>,</p>
      <p style="font-size: 14px; color: #5f5e5a; margin: 0 0 20px;">You have <strong>${data.totalDeals} deal(s)</strong> that require your immediate attention.</p>
    </div>
    <div style="padding: 0 32px;">
      <table style="width: 100%; border-collapse: collapse; font-size: 14px;">
        <thead>
          <tr style="background: #f1efe8;">
            <th style="padding: 10px 8px; text-align: left; font-size: 12px; color: #888780; font-weight: 600;">Deal Name</th>
            <th style="padding: 10px 8px; text-align: left; font-size: 12px; color: #888780; font-weight: 600;">Due Date</th>
            <th style="padding: 10px 8px; text-align: left; font-size: 12px; color: #888780; font-weight: 600;">Status</th>
            <th style="padding: 10px 8px; text-align: left; font-size: 12px; color: #888780; font-weight: 600;">Action</th>
          </tr>
        </thead>
        <tbody>${dealRowsHtml}</tbody>
      </table>
    </div>
    ${remainingHtml}
    <div style="padding: 24px 32px; border-top: 1px solid #e8e8e8; margin-top: 16px;">
      <p style="font-size: 12px; color: #888780; margin: 0;">This is an automated alert from ${senderName}. Please do not reply to this email.</p>
    </div>
  </div>
</body>
</html>`;

// ---- BUILD CHAT MESSAGE (for Bitrix24 Chat) ----
let chatBody = `📋 *Deal Alert — ${alertLabel}*\n\n`;
chatBody += `Hi ${emp.name || 'User'}, you have *${data.totalDeals} deal(s)* needing attention:\n\n`;

shownDeals.forEach((deal, i) => {
  const subject = deal.subject || deal.entityTitle || 'Unnamed Deal';
  const dueDate = deal.deadlineFormatted || 'No date';
  const url = deal.url || data.bitrixDomain;
  chatBody += `${i + 1}. *${subject}*\n`;
  chatBody += `   📅 ${dueDate} — ${dealStatusLabel(deal)}\n`;
  chatBody += `   🔗 ${url}\n\n`;
});

if (remainingCount > 0) {
  chatBody += `➕ *${remainingCount} more deal(s)* not shown.\n`;
  chatBody += `View all: ${dealListUrl}\n`;
}
chatBody += `\n— ${senderName}`;

return [{
  json: {
    ...data,
    payload: {
      bitrixTitle: `Deal Alert — ${alertLabel}`,
      bitrixBody: bitrixBody,
      chatBody: chatBody,
      emailSubject: `[${alertLabel}] ${data.totalDeals} Deal(s) Requiring Attention — ${emp.name}`,
      emailHtml: emailHtml,
      recipientEmail: emp.email || 'no-email@example.com',
      recipientName: emp.name || 'User',
      bitrixUserId: emp.bitrixUserId
    }
  }
}];
